export const bookSlugs = [
  "ayetul-kubra",
  "kucuk-sozler",
  "meyve-risalesi",
  "tabiat-risalesi"
] as const;

const bookLoaders: Record<string, () => Promise<BookModule>> = {
  "ayetul-kubra": () => import("./books/ayetul-kubra.generated"),
  "kucuk-sozler": () => import("./books/kucuk-sozler.generated"),
  "meyve-risalesi": () => import("./books/meyve-risalesi.generated"),
  "tabiat-risalesi": () => import("./books/tabiat-risalesi.generated")
};

export async function loadBook(bookSlug: string): Promise<LibraryBook | null> {
  const loadBookModule = bookLoaders[bookSlug];

  if (!loadBookModule) {
    return null;
  }

  return (await loadBookModule()).book;
}

export async function loadLibrary(): Promise<LibraryManifest> {
  const books = await Promise.all(bookSlugs.map((bookSlug) => loadBook(bookSlug)));

  return {
    generatedAt: libraryIndex.generatedAt,
    stats: libraryIndex.stats,
    books: books.filter((book): book is LibraryBook => Boolean(book))
  };
}
